from collections import defaultdict, Counter
import sys

sys.setrecursionlimit(10000)

def precompute_sets_by_sum():
    sets_by_sum = defaultdict(list)
    for mask in range(1<<9):
        s = set()
        total = 0
        for d in range(1,10):
            if mask & (1<<(d-1)):
                s.add(d)
                total += d
        if 1 <= total <= 45:
            sets_by_sum[total].append(s)
    return sets_by_sum

