                        candidate_left = next_string + min_rest_str
                        if L % 2 == 0:
                            candidate_full = candidate_left + candidate_left[::-1]
                        else:
                            candidate_full = candidate_left + str(center_val) + candidate_left[::-1]
                        if candidate_full > s:
