                        break
                if not found_flag:
                    candidate_val = None
                else:
                    if L % 2 == 0:
                        candidate_full = current_string + current_string[::-1]
                    else:
                        candidate_full = current_string + str(center_val) + current_string[::-1]
                    candidate_val = int(candidate_full)
            else:
