import itertools
from math import factorial
from collections import Counter

def generate_valid_sets():
    valid_sets = []
    for r in range(1, 10):
        for combo in itertools.combinations(range(1,10), r):
            s = sum(combo)
            num_odd = sum(1 for d in combo if d % 2 == 1)
            if s % 2 == 0:
                if num_odd == 0:
                    valid_sets.append((s, combo, None))
            else:
                if num_odd == 1:
                    for d in combo:
                        if d % 2 == 1:
                            valid_sets.append((s, combo, d))
                            break
    return valid_sets

def generate_palindrome_from_A(A, L, center_digit):
    half_len = (L + 1) // 2
    if L % 2 == 0:
        return A + A[::-1]
    else:
        return A + A[:half_len - 1][::-1]

def smallest_lex_permutation(counts, L, center_digit):
    half_len = (L + 1) // 2
    if L % 2 == 1:
        if center_digit not in counts or counts[center_digit] == 0:
            return None
        counts[center_digit] -= 1
        arr = []
        digits = sorted(counts.keys())
        for d in digits:
            arr.extend([d] * counts[d])
        arr.sort()
        prefix = arr
        A = prefix + [center_digit]
    else:
        arr = []
        for d, cnt in counts.items():
            arr.extend([d] * cnt)
        arr.sort()
        A = arr
    return ''.join(str(d) for d in A)

def solve(n):
    if n >= 10**15:
        n_str = str(n)
        L_min = len(n_str)
    else:
        n_str = str(n)
        L_min = len(n_str)
    all_valid_sets = generate_valid_sets()
    best = None
    for L in range(L_min, 46):
        if best is not None and L > len(str(best)): 
            break
        for s_val, combo, center in all_valid_sets:
            if s_val != L:
                continue
            counts = [0] * 10
            total_digits = set()
            for d in combo:
                total_digits.add(d)
                if L % 2 == 1:
                    if d == center:
                        counts[d] = (d + 1) // 2
                    else:
                        counts[d] = d // 2
                else:
                    counts[d] = d // 2
            count_dict = {d: counts[d] for d in range(1,10)}
            A_str = smallest_lex_permutation(count_dict, L, center)
            if A_str is None:
                continue
            num = generate_palindrome_from_A(A_str, L, center)
            num_int = int(num)
            if len(num) > L_min:
                if best is None or num_int < best:
                    best = num_int
            else:
                if num_int > n:
                    if best is None or num_int < best:
                        best = num_int
        if best is not None and L == len(str(best)):
            break
    if best is None:
        return 22
    return best
